/**  错误分类码。前端按 `code` 决定提示文案与重试策略。 */
export type ErrorCode = 
/**  未归类的内部错误 */
"internal" | 
/**  资源不存在（连接、会话、表等） */
"notFound" | 
/**  入参非法 */
"invalidInput" | 
/**  连接失败（网络、拒绝、不可达） */
"connection" | 
/**  认证失败（密码/密钥/Token 错误） */
"auth" | 
/**  权限不足 */
"permission" | 
/**  操作超时 */
"timeout" | 
/**  数据库错误 */
"database" | 
/**  SSH 相关错误 */
"ssh" | 
/**  终端/PTY 错误 */
"terminal" | 
/**  本地存储 / 凭据库错误 */
"storage" | 
/**  IO 错误 */
"io";

